const job = $input.first().json.data || $input.first().json;

// Map service types to required skills
const skillMap = {
  'cctv': ['cctv', 'surveillance', 'networking', 'general'],
  'networking': ['networking', 'cabling', 'general'],
  'wifi': ['wifi', 'networking', 'general'],
  'nas': ['nas', 'storage', 'networking', 'general'],
  'general maintenance': ['maintenance', 'general']
};

const serviceType = (job.service_type || '').toLowerCase();
const requiredSkills = skillMap[serviceType] || ['general'];

// Pass ALL job data forward so downstream nodes can access it
return {
  jobId: job.id,
  clientId: job.client_id,
  serviceType: job.service_type,
  requiredSkills: requiredSkills,
  status: job.status,
  description: job.job_description,
  address: job.client_address || job.address,
  companyName: job.company_name
};

// Job data comes from the 'Prepare Assignment Data' node (previous input)
const jobData = $input.first().json;

// Workers come from the HTTP response (we need to get it from previous nodes)
// In n8n v1 execution order, $input contains the output of the LAST node that ran
// Since workers API is the last HTTP call, $input has workers data
// But we need jobData from the earlier code node
// FIX: Use $('Node Name').first().json to reference specific nodes
let workers;
try {
  workers = $('GET Available Workers').first().json.data || $('GET Available Workers').first().json;
  if (!Array.isArray(workers)) workers = [];
} catch (e) {
  workers = [];
}

let jobInfo;
try {
  jobInfo = $('Prepare Assignment Data').first().json;
} catch (e) {
  jobInfo = jobData;
}

if (!workers.length) {
  return { error: 'No available workers found', jobId: jobInfo.jobId };
}

// Score each worker
const scored = workers.filter(w => w.role === 'Technician' || w.role === 'technician').map(w => {
  let score = 0;

  // Skill match (50 points)
  const workerSpecialties = (w.specialties || '').toLowerCase();
  const matchedSkills = (jobInfo.requiredSkills || []).filter(s => workerSpecialties.includes(s));
  score += jobInfo.requiredSkills.length > 0 ? (matchedSkills.length / jobInfo.requiredSkills.length) * 50 : 25;

  // Active status (20 points)
  if (w.active) score += 20;

  // Rating (15 points)
  score += ((w.rating || 3) / 5) * 15;

  // Experience (15 points)
  score += Math.min((w.experience_years || 1) / 5, 1) * 15;

  return { ...w, score: Math.round(score) };
});

scored.sort((a, b) => b.score - a.score);

if (!scored.length) {
  return { error: 'No qualified technicians found', jobId: jobInfo.jobId };
}

return {
  jobId: jobInfo.jobId,
  clientId: jobInfo.clientId,
  serviceType: jobInfo.serviceType,
  companyName: jobInfo.companyName,
  recommendedWorker: scored[0],
  allRanked: scored.slice(0, 5)
};

